import 'package:firebase_database/firebase_database.dart'; import 'package:firebase_auth/firebase_auth.dart'; import 'package:injectable/injectable.dart'; @singleton class CallSignalingService { final _db = FirebaseDatabase.instance; String get _uid => FirebaseAuth.instance.currentUser?.uid ?? ''; Future<void> sendCallRequest(String targetUid, String callId) => _db.ref('call_signals/$targetUid').set({'from': _uid, 'callId': callId, 'ts': ServerValue.timestamp}); Future<void> sendCallAccepted(String callerUid) => _db.ref('call_signals/$callerUid/status').set('accepted'); Future<void> sendCallDeclined(String callerUid) => _db.ref('call_signals/$callerUid/status').set('declined'); Future<void> sendCallEnded(String otherUid) => _db.ref('call_signals/$otherUid').remove(); }